// import React, { useState } from 'react';
// import { 
//   Users, Bell, Home, LogOut, 
//   Zap, CheckCircle2, ArrowLeft, 
//   Download, Clock, Filter, TrendingUp, AlertCircle
// } from 'lucide-react';

import React, { useState } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, LogOut, 
  Zap, CheckCircle2, ChevronRight, Download, X, Menu, 
  ShieldAlert, Landmark, Save, Eye, Filter, Clock, 
  AlertCircle, TrendingUp, ZapOff, Check, Ban
} from 'lucide-react';

/**
 * HOMELY - INTEGRATED PROPERTY MANAGEMENT SYSTEM
 * * Features included:
 * - Role-based Dashboard (Resident/Landlord)
 * - Automatic Electricity Calculation (Units * Price)
 * - 5-Day Grace Period Late Fee Logic
 * - Landlord Approval/Rejection Queue
 * - Financial Statistics Tracking
 */

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');

  // --- Central Data Management ---
  const [tenants, setTenants] = useState([
    { 
      id: 1, 
      name: 'Rajesh Kumar', 
      room: 'A-101', 
      status: 'Pending', 
      amount: 12500, 
      dueDate: '2026-04-05', 
      prevReading: 1020,
      currReading: 1150,
      unitPrice: 8,
      lateFeePerDay: 50,
      history: [
        { month: 'March', amount: 13200, status: 'Paid', date: '02/03/2026' }
      ]
    },
    { 
      id: 2, 
      name: 'Anita Sharma', 
      room: 'B-204', 
      status: 'Pending Approval', 
      amount: 15000, 
      dueDate: '2026-04-05', 
      prevReading: 500, 
      currReading: 580, 
      unitPrice: 8, 
      lateFeePerDay: 50,
      history: []
    },
  ]);

  // --- Core Utility Logic ---
  const calculateElectricity = (t) => (t.currReading - t.prevReading) * t.unitPrice;

  const calculateLateFee = (t) => {
    const due = new Date(t.dueDate);
    const today = new Date();
    const diffTime = today - due;
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    // Apply fee only after 5-day grace period
    return diffDays > 5 ? (diffDays - 5) * t.lateFeePerDay : 0;
  };

  const getTotalPayable = (t) => t.amount + calculateElectricity(t) + calculateLateFee(t);

  const handleLandlordAction = (tenantId, action) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        if (action === 'approve') {
          return { 
            ...t, 
            status: 'Paid',
            history: [{ month: 'Current', amount: getTotalPayable(t), status: 'Paid', date: new Date().toLocaleDateString() }, ...t.history]
          };
        }
        return { ...t, status: 'Pending' };
      }
      return t;
    }));
  };

  // --- Auth Screen ---
  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-4">
        <div className="w-full max-w-4xl bg-white rounded-[3rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-2">
          <div className="bg-slate-900 p-16 text-white flex flex-col justify-between hidden md:flex">
            <div className="flex items-center gap-3 italic font-black text-2xl">
              <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center not-italic">H</div> Homely
            </div>
            <h1 className="text-5xl font-black leading-tight italic">Manage Your<br/>Property.<br/>Better.</h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-xs italic">Smart Management System</p>
          </div>
          <div className="p-8 md:p-16 flex flex-col justify-center">
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-10">
              <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Resident</button>
              <button onClick={() => setLoginMode('admin')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Landlord</button>
            </div>
            <form onSubmit={(e) => {e.preventDefault(); setUserRole(loginMode); setActiveTab(loginMode === 'admin' ? 'Dashboard' : 'Overview');}} className="space-y-4">
              <input type="text" placeholder="Mobile / ID" className="w-full bg-slate-50 border-none rounded-2xl py-5 px-8 font-black outline-none" required />
              <input type="password" placeholder="Password" className="w-full bg-slate-50 border-none rounded-2xl py-5 px-8 font-black outline-none" required />
              <button className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl uppercase tracking-[0.2em] text-xs shadow-2xl hover:bg-indigo-600 transition-all">Sign In</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} activeTab={activeTab} setActiveTab={setActiveTab} onAction={handleLandlordAction} logout={() => setUserRole(null)} calcTotal={getTotalPayable} />
  ) : (
    <TenantPortal tenant={tenants[0]} logout={() => setUserRole(null)} calcElec={calculateElectricity} calcLate={calculateLateFee} calcTotal={getTotalPayable} />
  );
};

// --- Landlord View ---
const AdminPortal = ({ tenants, setTenants, notifications, activeTab, setActiveTab, logout }) => {
  const [profileOpen, setProfileOpen] = useState(false);
  const [selectedTenant, setSelectedTenant] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // --- SRS LOGIC: CALCULATIONS ---
  const calculateElectricity = (t) => (t.currReading - t.prevReading) * t.unitPrice;
  
  const calculateLateFee = (t) => {
    const due = new Date(t.dueDate);
    const today = new Date();
    const diffTime = today - due;
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    // SRS 2.1.1: 5-day grace period
    return diffDays > 5 ? (diffDays - 5) * t.lateFeePerDay : 0;
  };

  const getTotalDue = (t) => t.amount + calculateElectricity(t) + calculateLateFee(t);

  // --- SRS 2.1.2: APPROVAL ACTIONS ---
  const handleApproval = (id, status) => {
    setTenants(prev => prev.map(t => {
      if (t.id === id) {
        return { ...t, status: status === 'approve' ? 'Paid' : 'Rejected' };
      }
      return t;
    }));
  };

  const pendingApprovals = tenants.filter(t => t.status === 'Pending Approval');
  const totalRevenue = tenants.reduce((acc, t) => t.status === 'Paid' ? acc + getTotalDue(t) : acc, 0);

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      {/* Sidebar - Same structure as your code */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-slate-900 text-white p-8 flex flex-col shrink-0 transition-transform md:relative md:translate-x-0 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex items-center justify-between mb-12">
          <div className="flex items-center gap-3 font-black italic text-xl">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center not-italic">H</div> Homely
          </div>
          <button onClick={() => setSidebarOpen(false)} className="md:hidden"><X/></button>
        </div>
        <nav className="space-y-2 flex-1">
          {['Dashboard', 'Tenants', 'Billing', 'Settings'].map(tab => (
            <button key={tab} onClick={() => {setActiveTab(tab); setSidebarOpen(false);}} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-900/50' : 'text-slate-500 hover:text-white'}`}>
              {tab === 'Dashboard' && <Home size={18}/>}
              {tab === 'Tenants' && <Users size={18}/>}
              {tab === 'Billing' && <Zap size={18}/>}
              {tab === 'Settings' && <Settings size={18}/>}
              {tab}
            </button>
          ))}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="h-24 bg-white border-b px-6 md:px-12 flex items-center justify-between">
           <div className="flex items-center gap-4">
             <button onClick={() => setSidebarOpen(true)} className="md:hidden p-2 bg-slate-50 rounded-lg"><Menu size={20}/></button>
             <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{activeTab}</h2>
           </div>
           <div className="relative">
              <button onClick={() => setProfileOpen(!profileOpen)} className="flex items-center gap-3 p-2 pr-6 bg-slate-50 border rounded-2xl hover:bg-slate-100 transition-all">
                 <div className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black">AD</div>
                 <span className="text-xs font-black uppercase italic hidden sm:inline">Manager <ChevronRight size={12}/></span>
              </button>
              {profileOpen && (
                 <div className="absolute right-0 mt-4 w-52 bg-white rounded-2xl shadow-2xl border p-2 z-50">
                    <button onClick={logout} className="w-full flex items-center gap-3 p-4 text-[10px] font-black text-red-500 hover:bg-red-50 rounded-xl uppercase border-t mt-2 pt-4"><LogOut size={14}/> Sign Out</button>
                 </div>
              )}
           </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 md:p-12">
          {activeTab === 'Dashboard' && (
            <div className="space-y-12 animate-in fade-in duration-500">
               {/* Stats Grid */}
               <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  <div className="bg-white p-10 rounded-[3rem] border shadow-sm flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-2">Total Collected</p><h3 className="text-4xl font-black italic text-emerald-600">₹{totalRevenue.toLocaleString()}</h3></div>
                      <Landmark className="text-emerald-500/20" size={48}/>
                  </div>
                  <div className="bg-white p-10 rounded-[3rem] border shadow-sm flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-2">Needs Approval</p><h3 className="text-4xl font-black italic text-amber-500">{pendingApprovals.length}</h3></div>
                      <Clock className="text-amber-500/20" size={48}/>
                  </div>
                  <div className="bg-slate-900 p-10 rounded-[3rem] shadow-2xl text-white">
                      <p className="text-[10px] font-black uppercase mb-2 text-slate-400">Late Fee Rate</p>
                      <h3 className="text-4xl font-black italic">₹50 <span className="text-sm not-italic text-slate-500">/ day</span></h3>
                  </div>
               </div>

               {/* SRS 2.1.2: APPROVAL QUEUE */}
               <div className="bg-white rounded-[3.5rem] border shadow-sm overflow-hidden">
                  <div className="p-10 border-b flex justify-between items-center">
                    <h3 className="text-xs font-black uppercase italic">Payment Approval Queue</h3>
                    <Filter size={16} className="text-slate-400"/>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left">
                       <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase border-b">
                         <tr><th className="px-10 py-6">Tenant</th><th className="px-10 py-6">Total Due</th><th className="px-10 py-6">Late Fee</th><th className="px-10 py-6 text-right">Action</th></tr>
                       </thead>
                       <tbody>
                          {pendingApprovals.length > 0 ? pendingApprovals.map(t => (
                            <tr key={t.id} className="border-b last:border-0 hover:bg-slate-50 transition-colors">
                               <td className="px-10 py-6 font-bold text-xs">{t.name} <span className="block text-[10px] text-slate-400 font-normal">{t.room}</span></td>
                               <td className="px-10 py-6 font-black italic text-xs">₹{getTotalDue(t).toLocaleString()}</td>
                               <td className="px-10 py-6 text-xs text-red-500">₹{calculateLateFee(t)}</td>
                               <td className="px-10 py-6 text-right">
                                  <div className="flex gap-2 justify-end">
                                    <button onClick={() => handleApproval(t.id, 'approve')} className="p-2 bg-emerald-100 text-emerald-600 rounded-lg hover:bg-emerald-600 hover:text-white transition-all"><Check size={16}/></button>
                                    <button onClick={() => handleApproval(t.id, 'reject')} className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-600 hover:text-white transition-all"><Ban size={16}/></button>
                                  </div>
                               </td>
                            </tr>
                          )) : (
                            <tr><td colSpan="4" className="px-10 py-20 text-center text-slate-300 uppercase font-black text-[10px] tracking-widest">No pending requests</td></tr>
                          )}
                       </tbody>
                    </table>
                  </div>
               </div>
            </div>
          )}

          {/* SRS 2.2: ELECTRICITY BILLING VIEW */}
          {activeTab === 'Billing' && (
            <div className="space-y-8 animate-in slide-in-from-bottom-4">
              <h3 className="text-3xl font-black italic uppercase">Meter Management</h3>
              <div className="grid grid-cols-1 gap-6">
                {tenants.map(t => (
                  <div key={t.id} className="bg-white p-8 rounded-[2.5rem] border shadow-sm flex flex-col md:flex-row items-center gap-8">
                    <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center font-black italic text-2xl">{t.room}</div>
                    <div className="flex-1">
                      <p className="text-lg font-black italic">{t.name}</p>
                      <div className="flex gap-8 mt-2">
                        <div><p className="text-[9px] font-black text-slate-400 uppercase">Prev Reading</p><p className="font-bold">{t.prevReading}</p></div>
                        <div className="text-indigo-600"><p className="text-[9px] font-black uppercase">Current Reading</p><p className="font-bold underline underline-offset-4 cursor-pointer">{t.currReading}</p></div>
                        <div><p className="text-[9px] font-black text-slate-400 uppercase">Units</p><p className="font-bold">{t.currReading - t.prevReading}</p></div>
                      </div>
                    </div>
                    <div className="text-right">
                       <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Elec. Charge</p>
                       <h4 className="text-2xl font-black italic">₹{calculateElectricity(t)}</h4>
                    </div>
                    <button className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-600 transition-all">Update Meter</button>
                  </div>
                ))}
              </div>
            </div>
          )}
          
          {/* Other tabs follow similar logic... */}
        </main>
      </div>
    </div>
  );
};

